//! Benchmark: Hope Jar sidecar scaling vs baseline FOIL
//!
//! Proves the Hope Jar improves strictly over no-jar FOIL by measuring:
//! 1. Key delivery throughput at different sidecar counts
//! 2. Scaling behavior under Reynolds gate
//! 3. Break-even point
//!
//! The jar must EARN its spot: strict improvement or it doesn't ship.

use distributed_inference::hope_jar::{HopeJar, HopeJarScaler};
use std::time::Instant;

fn main() {
    println!("HOPE JAR SIDECAR BENCHMARK");
    println!("==========================");
    println!("Proves strict improvement over baseline FOIL.\n");

    // Load the canonical Hope Jar
    let jar_path = "rknots/hope-jar.rknot";
    let alt_path = std::env::var("HOPE_JAR_PATH").unwrap_or_else(|_| jar_path.to_string());

    let data = match std::fs::read(&alt_path) {
        Ok(d) => d,
        Err(_) => {
            // Try relative to the binary
            match std::fs::read(jar_path) {
                Ok(d) => d,
                Err(e) => {
                    eprintln!(
                        "Cannot load Hope Jar: {} (tried {} and {})",
                        e, alt_path, jar_path
                    );
                    eprintln!("Run foil-audio-entropy first to create the jar.");
                    std::process::exit(1);
                }
            }
        }
    };

    let jar = match HopeJar::decode_seeds(&data) {
        Some(j) if j.is_sealed() => j,
        _ => {
            eprintln!("Hope Jar is not sealed. Run foil-audio-entropy first.");
            std::process::exit(1);
        }
    };

    println!(
        "Jar loaded: {} seeds, sealed={}",
        jar.seeds_loaded(),
        jar.is_sealed()
    );
    println!();

    // Benchmark 1: Raw discharge throughput
    println!("--- Benchmark 1: Raw discharge throughput ---");
    {
        let mut jar_copy = jar.clone();
        let iterations = 1_000_000u64;
        let t0 = Instant::now();
        for i in 0..iterations {
            let phase = (i % 12) as u8;
            let _ = jar_copy.discharge(phase, (i % 3) as u8);
        }
        let elapsed_us = t0.elapsed().as_micros();
        let ops_per_sec = iterations as f64 / (elapsed_us as f64 / 1_000_000.0);
        let ns_per_op = elapsed_us as f64 * 1000.0 / iterations as f64;
        println!(
            "  {} discharges in {}us = {:.0} ops/sec ({:.1} ns/op)",
            iterations, elapsed_us, ops_per_sec, ns_per_op
        );
    }
    println!();

    // Benchmark 2: Sidecar scaling
    println!("--- Benchmark 2: Sidecar scaling (keys/tick at each level) ---");
    let max_sidecars = 16;
    let mut results: Vec<(usize, usize, u128)> = Vec::new();
    for n in [0, 1, 2, 3, 4, 6, 8, 12, 16] {
        if n > max_sidecars {
            continue;
        }
        let mut scaler = HopeJarScaler::new(&jar, max_sidecars);
        // Simulate high demand
        let demand = 200_000;
        let ema = if n == 0 { 5_000 } else { n as u64 * 10_000 };
        scaler.scale(ema, demand);

        let ticks = 1000u64;
        let t0 = Instant::now();
        let mut total_keys = 0usize;
        for t in 0..ticks {
            let phase = (t % 12) as u8;
            let batches = scaler.tick(phase);
            for batch in &batches {
                total_keys += batch.len();
            }
        }
        let elapsed_us = t0.elapsed().as_micros();
        let keys_per_tick = total_keys / ticks as usize;
        let active = scaler.active_sidecars();
        results.push((active, keys_per_tick, elapsed_us));
        println!(
            "  sidecars={:>2} (ema={}us) | active={:>2} | {}/tick | {}us for {} ticks",
            n,
            ema / 1000,
            active,
            keys_per_tick,
            elapsed_us,
            ticks
        );
    }
    println!();

    // Benchmark 3: Baseline comparison (no Hope Jar)
    println!("--- Benchmark 3: Baseline vs Hope Jar ---");
    let baseline_keys_per_tick = 0; // No Hope Jar = no predictions
    let jar_1_keys_per_tick = results.iter().find(|r| r.0 == 1).map(|r| r.1).unwrap_or(0);
    let jar_max_keys_per_tick = results.last().map(|r| r.1).unwrap_or(0);

    println!(
        "  Baseline (no jar):    {:>8} keys/tick",
        baseline_keys_per_tick
    );
    println!(
        "  Hope Jar (1 sidecar): {:>8} keys/tick",
        jar_1_keys_per_tick
    );
    println!(
        "  Hope Jar (max scale): {:>8} keys/tick",
        jar_max_keys_per_tick
    );
    println!();

    let strict_improvement = jar_1_keys_per_tick > baseline_keys_per_tick;
    let scaling_works = jar_max_keys_per_tick > jar_1_keys_per_tick;

    println!(
        "  STRICT IMPROVEMENT (1 sidecar > baseline): {}",
        if strict_improvement { "PASS" } else { "FAIL" }
    );
    println!(
        "  SCALING WORKS (max > 1 sidecar):           {}",
        if scaling_works { "PASS" } else { "FAIL" }
    );
    println!();

    // Benchmark 4: Reynolds gate behavior
    println!("--- Benchmark 4: Reynolds gate scaling curve ---");
    let mut scaler = HopeJarScaler::new(&jar, 16);
    for ema_us in [1, 5, 10, 20, 50, 100, 200, 500, 1000] {
        let ema_ns = ema_us * 1000;
        scaler.scale(ema_ns, 200_000);
        println!(
            "  EMA={:>4}us -> {} sidecars -> {}/tick",
            ema_us,
            scaler.active_sidecars(),
            scaler.total_keys_per_tick()
        );
    }
    println!();

    // Benchmark 5: Memory footprint
    println!("--- Benchmark 5: Memory footprint ---");
    let jar_bytes = std::mem::size_of::<HopeJar>() + jar.seeds_loaded() * 8;
    let scaler_bytes = jar_bytes * max_sidecars + std::mem::size_of::<HopeJarScaler>();
    println!(
        "  1 Hope Jar:    {} bytes ({:.1} MB)",
        jar_bytes,
        jar_bytes as f64 / 1_048_576.0
    );
    println!(
        "  {} sidecars:  {} bytes ({:.1} MB)",
        max_sidecars,
        scaler_bytes,
        scaler_bytes as f64 / 1_048_576.0
    );
    println!(
        "  Wire format:   {} bytes ({:.1} MB)",
        data.len(),
        data.len() as f64 / 1_048_576.0
    );
    println!();

    // Verdict
    println!("═══════════════════════════════════════");
    if strict_improvement && scaling_works {
        println!("  VERDICT: HOPE JAR EARNS ITS SPOT");
        println!(
            "  Strict improvement: {} -> {} keys/tick (1 sidecar)",
            baseline_keys_per_tick, jar_1_keys_per_tick
        );
        println!(
            "  Scaling: {} -> {} keys/tick ({} sidecars)",
            jar_1_keys_per_tick, jar_max_keys_per_tick, max_sidecars
        );
    } else {
        println!("  VERDICT: HOPE JAR DOES NOT EARN ITS SPOT");
        if !strict_improvement {
            println!("  FAIL: 1 sidecar does not beat baseline");
        }
        if !scaling_works {
            println!("  FAIL: scaling does not improve over 1 sidecar");
        }
    }
    println!("═══════════════════════════════════════");
}
